    /** Resolve [key] for [locale] (language prefix ok), falling back to English. */
    fun resolve(locale: String, key: String): String {
        val lang = locale.substringBefore('-').lowercase()
        return stringsByLocale[lang]?.get(key)
            ?: stringsByLocale.getValue("en")[key]
            ?: key
    }
